body {
    scroll-behavior: smooth;
}
/* Custom styling for better readability and focus */
.text-300 { 
    font-size: 1.875rem; /* Equivalent to text-3xl */
}

/* Ensure the hero section background image looks good on all devices */
.relative {
    background-image: linear-gradient(rgba(0, 0, 0, 0.4), rgba(0, 0, 0, 0.4)), url('https://source.unsplash.com/random/1600x700?family,support');
    background-size: cover;
    background-position: center;
}

/* Styling for the PDF cards to look clickable */
.cursor-pointer { 
    cursor: pointer;
}

/* Adjustments for better visual hierarchy on resource section */
#risorse .border-l-4 {
    transition: box-shadow 0.3s ease;
}

